import pytest

def is_palindrome(s: str) -> bool:
    s = s.lower().replace(' ', '')
    return s == s[::-1]

class TestIsPalindrome:
    def test_happy_path_palindrome(self):
        assert is_palindrome("racecar") == True
        assert is_palindrome("A man, a plan, a canal: Panama") == True
        assert is_palindrome("Was it a car or a cat I saw?") == True

    def test_happy_path_not_palindrome(self):
        assert is_palindrome("hello") == False
        assert is_palindrome("world") == False

    def test_edge_case_empty_string(self):
        assert is_palindrome("") == True

    def test_edge_case_single_character(self):
        assert is_palindrome("a") == True

    def test_edge_case_single_space(self):
        assert is_palindrome(" ") == True

    def test_edge_case_multiple_spaces(self):
        assert is_palindrome("   ") == True

    def test_case_insensitive(self):
        assert is_palindrome("Racecar") == True
        assert is_palindrome("Madam") == True

    def test_ignores_spaces(self):
        assert is_palindrome("race car") == True
        assert is_palindrome("A man a plan a canal Panama") == True

    def test_mixed_case_and_spaces(self):
        assert is_palindrome("Race car") == True
        assert is_palindrome("Madam I'm Adam") == True

    def test_with_punctuation(self):
        assert is_palindrome("Madam, I'm Adam.") == False # Punctuation is not removed
        assert is_palindrome("No 'x' in Nixon") == False # Punctuation is not removed

    def test_numbers(self):
        assert is_palindrome("121") == True
        assert is_palindrome("123") == False
        assert is_palindrome("A121A") == True
        assert is_palindrome("A man, a plan, a canal: Panama1") == False # Numbers are not removed
